def merge_sorted(a, b):
    """
    Merges two sorted lists into one sorted list.

    :param a: sorted list 
    :param b: sorted list
    :return: merged_list
    """
    while a and b:
        if a[0] < b[0]:
            yield a.pop(0)
        else:
            yield b.pop(0)
    if a:
        yield from a
    if b:
        yield from b
```

def count_inversions(arr):
    inversion_count = 0
    for i in range(len(arr) - 1):
        for j in range(i + 1, len(arr)):
            if arr[i] > arr[j]:
                inversion_count += 1
    return inversion_count
